package unverified;

import metadata.BehavioralDifference;
import metadata.DifferenceType;

import org.junit.jupiter.api.Test;

import static unverified.ClonePairGenericInvocationTestSupport.*;
import static org.junit.jupiter.api.Assertions.assertNotEquals;
import static org.junit.jupiter.api.Assertions.assertTrue;

class ClonePair9192DifferenceFindingTest {

    private final ClonePair9192 subject = new ClonePair9192();

    /**
     * Generated by Codex (GPT-5.5).
     * Difference type: return_value.
     * Difference manifestation: the methods return different values.
     */
    @Test
    @BehavioralDifference(DifferenceType.RETURN_VALUE)
    void methodsDisagreeOnGeneratedInput() {
        Object[] inputs = new Object[]{Double.MIN_VALUE};
        InvocationOutcome method1Outcome = capture(values -> subject.method1(((Double) values[0]).doubleValue()), inputs);
        InvocationOutcome method2Outcome = capture(values -> subject.method2(((Double) values[0]).doubleValue()), inputs);

        assertCoreOutcome(
            method1Outcome,
            "OK",
            "Double(-38.50886019576426)",
            null,
            "java.lang.Object[][Double(4.9E-324)]",
            "java.lang.Object[][Double(4.9E-324)]"
        );
        assertCoreOutcome(
            method2Outcome,
            "OK",
            "Double(-38.46740568497968)",
            null,
            "java.lang.Object[][Double(4.9E-324)]",
            "java.lang.Object[][Double(4.9E-324)]"
        );
        assertTextEquals("stdout", "", method1Outcome.stdout);
        assertTextEquals("stdout", "", method2Outcome.stdout);
        assertTextEquals("stderr", "", method1Outcome.stderr);
        assertTextEquals("stderr", "", method2Outcome.stderr);
        assertDifferent(method1Outcome, method2Outcome);
    }
}
